'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { languageInfo, type Lang } from '@/context/LanguageContext';

interface LanguageDetectionBannerProps {
  detectedLang: Lang;
  visible: boolean;
  onClose: () => void;
}

export function LanguageDetectionBanner({ detectedLang, visible, onClose }: LanguageDetectionBannerProps) {
  const [show, setShow] = useState(false);

  useEffect(() => {
    if (visible) {
      setShow(true);
      const timer = setTimeout(() => {
        setShow(false);
        onClose();
      }, 3000);
      return () => clearTimeout(timer);
    }
  }, [visible, onClose]);

  const info = languageInfo[detectedLang];

  return (
    <AnimatePresence>
      {show && (
        <motion.div
          initial={{ y: -36, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: -36, opacity: 0 }}
          transition={{ type: 'spring', stiffness: 300, damping: 25 }}
          className="flex items-center justify-center gap-2 mx-2 rounded-lg"
          style={{
            height: 36,
            backgroundColor: 'rgba(0,0,128,0.9)',
            color: 'white',
            fontSize: '12px',
            fontFamily: 'Manrope, sans-serif',
          }}
        >
          <span>🇮🇳</span>
          <span>{info.name} detected — शुभ अब {info.nativeName} में बोलेगा</span>
          <button
            onClick={() => {
              setShow(false);
              onClose();
            }}
            className="ml-1 rounded px-1 leading-none hover:bg-white/10"
            aria-label="Close language banner"
          >
            ✕
          </button>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { Check, Sparkles } from 'lucide-react';
import { motion, AnimatePresence } from 'motion/react';
import { useLang } from '@/context/LanguageContext';

interface ProfileCardProps {
  fields: Array<{
    key: string;
    label: string;
    value: string;
  }>;
  isExtracting?: boolean;
}

export function ProfileCard({ fields, isExtracting }: ProfileCardProps) {
  const { t, lang } = useLang();
  const [justExtracted, setJustExtracted] = useState<string[]>([]);

  // Track when fields are newly filled
  useEffect(() => {
    const newlyFilled = fields
      .filter(f => f.value && !justExtracted.includes(f.key))
      .map(f => f.key);

    if (newlyFilled.length > 0) {
      setJustExtracted(prev => [...prev, ...newlyFilled]);

      // Remove from justExtracted after animation
      setTimeout(() => {
        setJustExtracted(prev => prev.filter(k => !newlyFilled.includes(k)));
      }, 1500);
    }
  }, [fields]);

  const completedCount = fields.filter(f => f.value).length;
  const totalCount = fields.length;
  const completionPercentage = (completedCount / totalCount) * 100;

  return (
    <div 
      className="bg-white/40 backdrop-blur-md border border-white/60 rounded-2xl p-5 shadow-xl"
      style={{ backdropFilter: 'blur(16px)' }}
    >
      <div className="flex items-center gap-2 mb-4">
        <Sparkles className="w-5 h-5 text-[#FF9933]" />
        <h3 
          className="text-[#000080]" 
          style={{ fontWeight: 700, fontSize: '1rem', fontFamily: 'Lora, serif' }}
        >
          {t('profile.header')}
        </h3>
      </div>

      <div className="space-y-3">
        <AnimatePresence>
          {fields.map((f, index) => {
            const isNewlyExtracted = justExtracted.includes(f.key);

            return (
              <motion.div
                key={f.key}
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: index * 0.1 }}
                className="relative"
              >
                {/* Success Glow Effect */}
                {isNewlyExtracted && (
                  <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: [0, 0.3, 0] }}
                    transition={{ duration: 1.5 }}
                    className="absolute inset-0 rounded-lg bg-[#138808] blur-md -z-10"
                  />
                )}

                <div className={`flex items-center justify-between py-2.5 px-3 rounded-lg border transition-all ${
                  isNewlyExtracted 
                    ? 'bg-[#138808]/10 border-[#138808]/40 shadow-md' 
                    : 'bg-white/50 border-white/60'
                }`}>
                  <span 
                    className="text-muted-foreground" 
                    style={{ fontSize: '0.85rem', fontWeight: 500, fontFamily: 'Manrope, sans-serif' }}
                  >
                    {f.label}
                  </span>
                  <div className="flex items-center gap-2">
                    {f.value ? (
                      <>
                        <span 
                          style={{ fontSize: '0.9rem', fontWeight: 600, fontFamily: 'Manrope, sans-serif' }}
                          className="text-foreground"
                        >
                          {f.value}
                        </span>
                        <motion.div
                          initial={{ scale: 0 }}
                          animate={{ scale: 1 }}
                          transition={{ type: 'spring', stiffness: 500 }}
                        >
                          <div className="w-6 h-6 rounded-full bg-[#138808] flex items-center justify-center">
                            <Check className="w-4 h-4 text-white" />
                          </div>
                        </motion.div>
                      </>
                    ) : (
                      <div className="flex gap-1">
                        <div className="w-2 h-2 rounded-full bg-muted-foreground/30 animate-pulse" />
                        <div className="w-2 h-2 rounded-full bg-muted-foreground/30 animate-pulse" style={{ animationDelay: '0.2s' }} />
                        <div className="w-2 h-2 rounded-full bg-muted-foreground/30 animate-pulse" style={{ animationDelay: '0.4s' }} />
                      </div>
                    )}
                  </div>
                </div>
                {f.value && (
                  <motion.div
                    initial={{ width: 0 }}
                    animate={{ width: '100%' }}
                    transition={{ duration: 0.5 }}
                    className="absolute bottom-0 left-0 h-0.5 bg-gradient-to-r from-[#FF9933] to-[#138808] rounded-full"
                  />
                )}
              </motion.div>
            );
          })}
        </AnimatePresence>
      </div>

      {/* Completion Progress Bar */}
      <div className="mt-4 pt-4 border-t border-white/40">
        <div className="flex items-center justify-between mb-2">
          <span 
            className="text-muted-foreground" 
            style={{ fontSize: '0.75rem', fontWeight: 600, fontFamily: 'Manrope, sans-serif' }}
          >
            {t('profile.header')} {lang === 'hi' ? 'पूर्णता' : 'Completion'}
          </span>
          <span 
            className="text-[#138808]" 
            style={{ fontSize: '0.75rem', fontWeight: 700, fontFamily: 'Manrope, sans-serif' }}
          >
            {completedCount}/{totalCount}
          </span>
        </div>
        <div className="h-2 rounded-full bg-white/50 overflow-hidden">
          <motion.div 
            initial={{ width: 0 }}
            animate={{ width: `${completionPercentage}%` }}
            transition={{ type: 'spring', stiffness: 100, damping: 20 }}
            className="h-full rounded-full bg-gradient-to-r from-[#FF9933] via-[#e8882d] to-[#138808]"
          />
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import { motion } from 'motion/react';
import Image from 'next/image';

interface ShubhAvatarProps {
  size?: number;
  speaking?: boolean;
  listening?: boolean;
  processing?: boolean;
  // Phase 4 aliases
  isTalking?: boolean;
  isListening?: boolean;
  isProcessing?: boolean;
  showLabel?: boolean;
  showPlatform?: boolean;
  variant?: 'hero' | 'chat' | 'profile';
}

const AVATAR_IMAGE_SRC = '/assets/shubh_avatar_cutout.png';

// Feature coordinates in a fixed 380x422 canvas.
const F = {
  width: 380,
  height: 422,
  lex: 169.7,
  ley: 114.1,
  rex: 206.7,
  rey: 113.1,
  mx: 187,
  my: 148,
  eyePatchRx: 9.6,
  eyePatchRy: 5.8,
  mouthPatchRx: 13,
  mouthPatchRy: 7,
  eyeRx: 6.6,
  eyeRy: 4.8,
  pupilRx: 2.8,
  pupilRy: 3,
  blinkHalfWidth: 5,
  lipStroke: '#7B3A23',
  mouthFill: '#6F2B19',
  skinEye: '#d79b78',
  skinMouth: '#d08f6a',
};

export function ShubhAvatar({
  size = 300,
  speaking: speakingProp = false,
  listening: listeningProp = false,
  processing: processingProp = false,
  isTalking = false,
  isListening = false,
  isProcessing = false,
  showLabel = false,
  showPlatform = false,
  variant = 'hero',
}: ShubhAvatarProps) {
  const speaking = speakingProp || isTalking;
  const listening = listeningProp || isListening;
  const processing = processingProp || isProcessing;
  const [isBlinking, setIsBlinking] = useState(false);
  const [isMobile, setIsMobile] = useState(
    typeof window !== 'undefined' ? window.innerWidth < 640 : false
  );

  const actualSize = variant === 'chat' ? 32 : variant === 'profile' ? 64 : size;
  const responsiveSize = variant === 'hero' && isMobile ? 120 : actualSize;

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 640);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    const blink = () => {
      setIsBlinking(true);
      setTimeout(() => setIsBlinking(false), 150);
    };

    const interval = setInterval(blink, 3000 + Math.random() * 2000);
    return () => clearInterval(interval);
  }, []);

  const ringColor = speaking ? 'rgba(255,153,51,1)' : listening ? 'rgba(255,153,51,0.5)' : 'transparent';
  const ringSpeed = speaking ? 0.8 : 1.5;
  const containerOpacity = processing ? 0.8 : 1;
  const effectPadding = variant === 'hero' ? 60 : 24;
  const plateSize = responsiveSize * (variant === 'hero' ? 0.88 : 0.92);
  const plateTop = variant === 'hero' ? '58%' : '56%';
  const lipMotionState = speaking ? 'speaking' : listening || processing ? 'active' : 'idle';

  return (
    <div className="flex flex-col items-center">
      <motion.div
        className="relative"
        style={{
          width: responsiveSize + effectPadding,
          height: responsiveSize + effectPadding,
          opacity: containerOpacity,
          filter: processing ? 'saturate(0.7)' : 'saturate(1)',
          transition: 'filter 0.3s ease, opacity 0.3s ease',
        } as any}
      >
        {variant === 'hero' && (
          <motion.div
            className="absolute rounded-full"
            style={{
              width: plateSize,
              height: plateSize,
              left: '50%',
              top: plateTop,
              x: '-50%',
              y: '-50%',
              background: 'radial-gradient(circle, rgba(255,153,51,0.08) 0%, transparent 70%)',
            } as any}
            animate={{ scale: [1, 1.15, 1], opacity: [0.6, 1, 0.6] }}
            transition={{ duration: 4, repeat: Infinity, ease: 'easeInOut' }}
          />
        )}

        {speaking && (
          <motion.div
            className="absolute rounded-full"
            style={{
              width: plateSize + 10,
              height: plateSize + 10,
              left: '50%',
              top: plateTop,
              x: '-50%',
              y: '-50%',
              border: `2px solid ${ringColor}`,
              boxShadow: `0 0 20px ${ringColor}`,
              zIndex: 0,
            } as any}
            animate={{ scale: [1, 1.05, 1] }}
            transition={{ duration: ringSpeed, repeat: Infinity, ease: 'easeInOut' }}
          />
        )}

        {listening && !speaking && (
          <motion.div
            className="absolute rounded-full"
            style={{
              width: plateSize + 10,
              height: plateSize + 10,
              left: '50%',
              top: plateTop,
              x: '-50%',
              y: '-50%',
              border: `2px solid ${ringColor}`,
              zIndex: 0,
            } as any}
            animate={{ scale: [1, 1.04, 1] }}
            transition={{ duration: ringSpeed, repeat: Infinity, ease: 'easeInOut' }}
          />
        )}

        {processing && (
          <motion.div
            className="absolute rounded-full"
            style={{
              width: plateSize + 6,
              height: plateSize + 6,
              left: '50%',
              top: plateTop,
              x: '-50%',
              y: '-50%',
              border: '3px solid transparent',
              borderTopColor: '#FF9933',
              borderRightColor: '#FF9933',
              zIndex: 0,
            } as any}
            animate={{ rotate: 360 }}
            transition={{ duration: 1, repeat: Infinity, ease: 'linear' }}
          />
        )}

        {showPlatform && (
          <div
            className="absolute rounded-full"
            style={{
              width: plateSize + 24,
              height: plateSize + 24,
              left: '50%',
              top: plateTop,
              transform: 'translate(-50%, -50%)',
              background: 'radial-gradient(circle, rgba(255,255,255,0.06) 0%, transparent 70%)',
              zIndex: 0,
            }}
          />
        )}

        <div
          className="absolute rounded-full"
          style={{
            width: plateSize,
            height: plateSize,
            left: '50%',
            top: plateTop,
            transform: 'translate(-50%, -50%)',
            background: 'radial-gradient(circle at 30% 30%, #ffffff 0%, #f6f6f6 100%)',
            boxShadow: '0 16px 34px rgba(0,0,0,0.24), 0 4px 10px rgba(0,0,0,0.14)',
            zIndex: 0,
          }}
        />

        <div
          className="absolute rounded-full"
          style={{
            width: plateSize * 0.85,
            height: plateSize * 0.18,
            left: '50%',
            top: `calc(${plateTop} + ${plateSize * 0.38}px)`,
            transform: 'translate(-50%, -50%)',
            background: 'rgba(0,0,0,0.15)',
            filter: 'blur(14px)',
            zIndex: 0,
          }}
        />

        <svg
          width={responsiveSize}
          height={responsiveSize}
          viewBox={`0 0 ${F.width} ${F.height}`}
          fill="none"
          style={{
            position: 'absolute',
            left: '50%',
            top: '50%',
            transform: 'translate(-50%, -50%)',
            filter: 'drop-shadow(0 12px 20px rgba(0,0,0,0.2))',
            zIndex: 1,
          }}
        >
          {/* SVG Definitions — feathered patches & blur */}
          <defs>
            <radialGradient id="mouthPatchGrad" cx="50%" cy="50%" r="50%">
              <stop offset="0%" stopColor={F.skinMouth} stopOpacity="1" />
              <stop offset="55%" stopColor={F.skinMouth} stopOpacity="0.95" />
              <stop offset="80%" stopColor={F.skinMouth} stopOpacity="0.5" />
              <stop offset="100%" stopColor={F.skinMouth} stopOpacity="0" />
            </radialGradient>
            <radialGradient id="eyePatchGradL" cx="50%" cy="50%" r="50%">
              <stop offset="0%" stopColor={F.skinEye} stopOpacity="1" />
              <stop offset="60%" stopColor={F.skinEye} stopOpacity="0.95" />
              <stop offset="85%" stopColor={F.skinEye} stopOpacity="0.4" />
              <stop offset="100%" stopColor={F.skinEye} stopOpacity="0" />
            </radialGradient>
            <filter id="softEdge" x="-30%" y="-30%" width="160%" height="160%">
              <feGaussianBlur in="SourceGraphic" stdDeviation="1.2" />
            </filter>
          </defs>

          <image href={AVATAR_IMAGE_SRC} x="0" y="0" width={F.width} height={F.height} preserveAspectRatio="xMidYMid slice" />

          {/* ── Eyes ──
              Strategy: Same as mouth — original image eyes are the open state.
              - OPEN (default): Nothing overlaid, original artwork eyes show through
              - BLINK: Feathered patches cover original eyes + closed-eye curves drawn on top
          */}
          {isBlinking && (
            <>
              {/* Feathered patches to cover original open eyes during blink */}
              <ellipse cx={F.lex} cy={F.ley} rx={F.eyePatchRx * 1.4} ry={F.eyePatchRy * 1.5} fill="url(#eyePatchGradL)" filter="url(#softEdge)" />
              <ellipse cx={F.rex} cy={F.rey} rx={F.eyePatchRx * 1.4} ry={F.eyePatchRy * 1.5} fill="url(#eyePatchGradL)" filter="url(#softEdge)" />

              {/* Closed eye curves — gentle downward arcs matching the character's style */}
              <path
                d={`M ${F.lex - F.blinkHalfWidth} ${F.ley - 0.5} Q ${F.lex} ${F.ley + 2} ${F.lex + F.blinkHalfWidth} ${F.ley - 0.5}`}
                stroke="#4d372a"
                strokeWidth="1.8"
                strokeLinecap="round"
                fill="none"
                opacity="0.85"
              />
              <path
                d={`M ${F.rex - F.blinkHalfWidth} ${F.rey - 0.5} Q ${F.rex} ${F.rey + 2} ${F.rex + F.blinkHalfWidth} ${F.rey - 0.5}`}
                stroke="#4d372a"
                strokeWidth="1.8"
                strokeLinecap="round"
                fill="none"
                opacity="0.85"
              />
            </>
          )}

          {/* ── Mouth / Lip-sync ──
              Strategy: The original image has an open smiling mouth.
              - SPEAKING: Patch fades OUT → original smile shows through (open mouth)
              - IDLE:     Patch fades IN  → covers smile, a closed-mouth line is drawn on top
              This creates natural open↔close lip-sync using the actual artwork.
          */}

          {/* Mouth cover patch — hides the original open smile when idle */}
          <motion.ellipse
            cx={F.mx}
            cy={F.my + 1}
            rx={F.mouthPatchRx * 1.5}
            ry={F.mouthPatchRy * 1.6}
            fill="url(#mouthPatchGrad)"
            filter="url(#softEdge)"
            animate={{
              opacity:
                lipMotionState === 'speaking'
                  ? [1, 0.3, 0.8, 0.2, 0.7, 0.25, 1]
                  : lipMotionState === 'active'
                    ? [1, 0.6, 0.9, 0.5, 1]
                    : [1],
            }}
            transition={{
              duration: lipMotionState === 'speaking' ? 0.55 : lipMotionState === 'active' ? 1.2 : 0,
              repeat: lipMotionState !== 'idle' ? Infinity : 0,
              ease: [0.45, 0.05, 0.55, 0.95],
            }}
          />

          {/* Closed mouth line — gentle smile matching the character's style.
              Visible when idle, fades out when speaking to reveal original smile. */}
          <motion.g
            animate={{
              opacity:
                lipMotionState === 'speaking'
                  ? [1, 0.2, 0.85, 0.15, 0.8, 0.2, 1]
                  : lipMotionState === 'active'
                    ? [1, 0.5, 0.9, 0.45, 1]
                    : [1],
            }}
            transition={{
              duration: lipMotionState === 'speaking' ? 0.55 : lipMotionState === 'active' ? 1.2 : 0,
              repeat: lipMotionState !== 'idle' ? Infinity : 0,
              ease: [0.45, 0.05, 0.55, 0.95],
            }}
          >
            {/* Closed upper lip — gentle upward curve matching the smile shape */}
            <path
              d={`M ${F.mx - 9} ${F.my + 0.5}
                  C ${F.mx - 5} ${F.my - 1}, ${F.mx - 1.5} ${F.my - 1.8}, ${F.mx} ${F.my - 0.6}
                  C ${F.mx + 1.5} ${F.my - 1.8}, ${F.mx + 5} ${F.my - 1}, ${F.mx + 9} ${F.my + 0.5}`}
              stroke="#8B5E3C"
              strokeWidth="1.4"
              fill="none"
              strokeLinecap="round"
              opacity="0.85"
            />
            {/* Closed lower lip — subtle line just below */}
            <path
              d={`M ${F.mx - 7} ${F.my + 1}
                  Q ${F.mx} ${F.my + 3.5} ${F.mx + 7} ${F.my + 1}`}
              stroke="#8B5E3C"
              strokeWidth="0.9"
              fill="none"
              strokeLinecap="round"
              opacity="0.45"
            />
          </motion.g>
        </svg>
      </motion.div>

      {showLabel && (
        <div className="text-center mt-2">
          <p style={{ fontFamily: 'Lora, serif', fontSize: '18px', color: 'white', opacity: 0.8 }}>शुभ</p>
