'use client';

import React, { useState, useEffect } from 'react';
import { useLang } from '@/context/LanguageContext';
import { useApp } from '@/context/AppContext';
import { Search, Check, Clock, AlertCircle, ArrowRight } from 'lucide-react';
import { motion } from 'motion/react';
import { ShubhAvatarSmall } from '@/components/ShubhAvatar';
import { trackApplication, getSessionApplications } from '@/lib/api';

export function Track() {
  const { t, lang } = useLang();
  const { applications, sessionId } = useApp();
  const [refInput, setRefInput] = useState('');
  const [result, setResult] = useState<any>(null);
  const [searched, setSearched] = useState(false);
  const [loading, setLoading] = useState(false);
  const [sessionApps, setSessionApps] = useState<any[]>([]);

  useEffect(() => {
    getSessionApplications(sessionId).then(apps => {
      if (Array.isArray(apps)) setSessionApps(apps);
    }).catch(() => {});
  }, [sessionId]);

  const handleTrack = async () => {
    setSearched(true);
    setLoading(true);
    try {
      const data = await trackApplication(refInput);
      setResult(data);
    } catch {
      // Try local session apps or applications context as fallback
      const found = sessionApps.find((a: any) => a.reference_number === refInput)
        || (applications[refInput] ? { reference_number: refInput, ...applications[refInput] } : null);
      setResult(found || null);
    } finally {
      setLoading(false);
    }
  };

  const stages = [
    {
      key: 'submitted',
      label: lang === 'hi' ? 'जमा किया' : 'Submitted',
      date: '20 Mar 2026',
      icon: Check,
    },
    {
      key: 'state_verified',
      label: lang === 'hi' ? 'राज्य सत्यापित' : 'State Verified',
      date: '24 Mar 2026',
      icon: Check,
    },
    {
      key: 'central_processed',
      label: lang === 'hi' ? 'केंद्र प्रक्रिया' : 'Central Processed',
      date: null,
      icon: Clock,
    },
    {
      key: 'benefit_released',
      label: lang === 'hi' ? 'लाभ जारी' : 'Benefit Released',
      date: null,
      icon: ArrowRight,
    },
  ];

  const statusOrder = ['submitted', 'state_verified', 'central_processed', 'benefit_released'];
  const stageIndex = result ? statusOrder.indexOf(result.status) : -1;

  return (
    <div className="max-w-2xl mx-auto px-4 py-12">
      <div className="text-center mb-8">
        <h1 className="text-[#000080] mb-2" style={{ fontWeight: 700, fontSize: '1.75rem', fontFamily: 'Lora, serif' }}>
          {t('track.header')}
        </h1>
        <p className="text-muted-foreground">{t('track.sub')}</p>
      </div>

      <div className="flex rounded-full border-2 border-border bg-white shadow-sm overflow-hidden focus-within:border-[#FF9933] transition mb-8">
        <input
          value={refInput}
          onChange={e => setRefInput(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && handleTrack()}
          placeholder={t('track.placeholder')}
          className="flex-1 px-5 py-3 bg-transparent outline-none"
          style={{ fontFamily: 'Manrope, sans-serif' }}
        />
        <button
          onClick={handleTrack}
          className="px-6 py-3 bg-[#FF9933] text-white hover:bg-[#e8882d] transition flex items-center gap-2"
          style={{ fontWeight: 500 }}
        >
          <Search className="w-4 h-4" /> {t('track.btn')}
        </button>
      </div>

      {searched && !result && !loading && (
        <div className="text-center p-6 rounded-xl bg-white border border-border">
          <AlertCircle className="w-10 h-10 text-muted-foreground mx-auto mb-3" />
          <p className="text-muted-foreground">{t('track.notfound')}</p>
        </div>
      )}

      {searched && loading && (
        <div className="text-center p-8">
          <div className="w-8 h-8 border-4 border-[#FF9933] border-t-transparent rounded-full animate-spin mx-auto" />
        </div>
      )}

      {result && (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="bg-white rounded-2xl border-2 border-border p-6 shadow-lg"
        >
          <h3 className="text-center mb-1 text-[#000080]" style={{ fontWeight: 700, fontSize: '1.1rem', fontFamily: 'Lora, serif' }}>
            {result.scheme_name || result.schemeName}
          </h3>
          <p className="text-center text-muted-foreground mb-8" style={{ fontSize: '0.85rem' }}>
            Ref: {result.reference_number || result.ref}
          </p>

          {/* 4-Node Application Journey Timeline */}
          <div className="relative mb-8">
            {/* Connection line */}
            <div className="absolute top-6 left-[12.5%] right-[12.5%] h-1 bg-muted rounded-full">
              <motion.div
                className="h-full rounded-full"
                initial={{ width: 0 }}
                animate={{ width: `${Math.min(stageIndex / (stages.length - 1), 1) * 100}%` }}
                transition={{ duration: 1, ease: 'easeOut' }}
                style={{
                  backgroundColor: result.status === 'rejected' ? '#dc2626' : '#138808',
                }}
              />
            </div>

            <div className="flex items-start justify-between relative">
              {stages.map((stage, i) => {
                const isDone = i <= stageIndex;
                const isCurrent = i === stageIndex;
                const isPending = i > stageIndex;

                return (
                  <div key={stage.key} className="relative z-10 flex flex-col items-center" style={{ width: `${100 / stages.length}%` }}>
                    {/* Shubh avatar marker at current node */}
                    {isCurrent && (
                      <motion.div
                        initial={{ scale: 0, y: -10 }}
                        animate={{ scale: 1, y: -8 }}
                        transition={{ type: 'spring', stiffness: 300 }}
                        className="absolute -top-5"
                      >
                        <ShubhAvatarSmall />
                      </motion.div>
                    )}

                    <motion.div
                      initial={{ scale: 0.8 }}
                      animate={{ scale: 1 }}
                      transition={{ delay: i * 0.15 }}
                      className={`w-12 h-12 rounded-full flex items-center justify-center border-2 transition-all ${
                        isDone
                          ? 'bg-[#138808] border-[#138808] text-white shadow-md'
                          : isCurrent
                          ? 'bg-[#FF9933] border-[#FF9933] text-white shadow-lg'
                          : 'bg-white border-border text-muted-foreground'
                      }`}
                      style={{ marginTop: isCurrent ? 16 : 0 }}
                    >
                      <stage.icon className="w-5 h-5" />
                    </motion.div>

                    <span
                      className={`mt-2 text-center ${isDone || isCurrent ? 'text-foreground' : 'text-muted-foreground'}`}
                      style={{
                        fontSize: '0.75rem',
                        fontWeight: isDone || isCurrent ? 600 : 400,
                        fontFamily: 'Manrope, sans-serif',
                      }}
                    >
                      {stage.label}
                    </span>

                    {stage.date && (
                      <span className="text-muted-foreground mt-1" style={{ fontSize: '0.65rem' }}>
                        {stage.date}
                      </span>
                    )}
                    {isPending && (
                      <span className="text-muted-foreground mt-1" style={{ fontSize: '0.65rem' }}>
                        {lang === 'hi' ? 'बाकी' : 'Pending'}
                      </span>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          <div className="text-center space-y-1 text-muted-foreground" style={{ fontSize: '0.85rem' }}>
            <p>
              {lang === 'hi' ? 'जमा:' : 'Submitted:'} {result.submitted_at || result.date || '—'}
            </p>
            <p>
              {lang === 'hi' ? 'अपेक्षित:' : 'Expected:'} {result.expected_benefit_date || result.expected || '—'}
            </p>
          </div>
        </motion.div>
      )}
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useLang } from '@/context/LanguageContext';
import { listSchemes } from '@/lib/api';
import type { SchemeResult } from '@/lib/api';
import { Search, Download, Eye, Edit2, Trash2 } from 'lucide-react';

const exportCsv = (data: any[], filename: string) => {
  if (!data.length) return;
  const csv = [
    Object.keys(data[0]).join(','),
    ...data.map(r => Object.values(r).map(v => `"${String(v).replace(/"/g, '""')}"`).join(',')),
  ].join('\n');
  const blob = new Blob([csv], { type: 'text/csv' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  URL.revokeObjectURL(url);
};

export function AdminSchemes() {
  const { lang, t } = useLang();
  const [allSchemes, setAllSchemes] = useState<SchemeResult[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');

  useEffect(() => {
    listSchemes()
      .then(d => {
        const list: SchemeResult[] = Array.isArray(d) ? d : (d?.schemes || []);
        setAllSchemes(list);
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const filtered = allSchemes.filter(s =>
    s.name_english.toLowerCase().includes(search.toLowerCase()) ||
    (s.ministry || '').toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div>
      <h1 className="text-[#000080] mb-6" style={{ fontWeight: 700 }}>{t('admin.schemes')}</h1>

      <div className="flex flex-wrap items-center gap-3 mb-6">
        <div className="flex-1 min-w-[200px] flex items-center gap-2 px-3 py-2 rounded-lg border border-border bg-white">
          <Search className="w-4 h-4 text-muted-foreground" />
          <input
            value={search} onChange={e => setSearch(e.target.value)}
            placeholder={t('admin.search_schemes')}
            className="flex-1 bg-transparent outline-none" style={{ fontSize: '0.85rem' }}
          />
        </div>
        <button
          onClick={() => exportCsv(filtered.map(s => ({
            id: s.scheme_id,
            name: s.name_english,
            ministry: s.ministry || '',
            level: s.level,
            benefit_inr: s.benefit_annual_inr,
            has_monetary: s.has_monetary_benefit,
          })), 'jan_saathi_schemes.csv')}
          className="px-4 py-2 rounded-lg border border-border flex items-center gap-2 hover:bg-muted"
          style={{ fontSize: '0.85rem' }}
        >
          <Download className="w-4 h-4" /> {t('admin.export_csv')}
        </button>
      </div>

      {loading ? (
        <div className="p-8 text-center text-muted-foreground">
          {lang === 'hi' ? 'लोड हो रहा है...' : 'Loading...'}
        </div>
      ) : (
        <div className="bg-white rounded-xl border border-border overflow-x-auto">
          <table className="w-full" style={{ fontSize: '0.8rem' }}>
            <thead>
              <tr className="border-b border-border text-left text-muted-foreground bg-muted/30">
                <th className="p-3">Name</th>
                <th className="p-3">Ministry</th>
                <th className="p-3">Level</th>
                <th className="p-3">Benefit</th>
                <th className="p-3">Status</th>
                <th className="p-3">Actions</th>
              </tr>
            </thead>
            <tbody>
              {filtered.length === 0 ? (
                <tr>
                  <td colSpan={6} className="p-6 text-center text-muted-foreground">
                    {lang === 'hi' ? 'कोई योजना नहीं मिली' : 'No schemes found'}
                  </td>
                </tr>
              ) : filtered.map(s => (
                <tr key={s.scheme_id} className="border-b border-border/50 hover:bg-muted/20">
                  <td className="p-3" style={{ fontWeight: 500 }}>
                    {lang === 'hi' ? (s.name_hindi || s.name_english) : s.name_english}
                    {s.acronym && (
                      <span className="ml-1.5 text-muted-foreground" style={{ fontSize: '0.7rem' }}>({s.acronym})</span>
                    )}
                  </td>
                  <td className="p-3 text-muted-foreground">{s.ministry || '—'}</td>
                  <td className="p-3">
                    <span
                      className="px-2 py-0.5 rounded-full"
                      style={{
                        fontSize: '0.7rem',
                        backgroundColor: s.level === 'central' ? 'rgba(0,0,128,0.1)' : 'rgba(19,136,8,0.1)',
                        color: s.level === 'central' ? '#000080' : '#138808',
                      }}
                    >
                      {s.level}
                    </span>
                  </td>
                  <td className="p-3 text-[#138808]" style={{ fontWeight: 600 }}>
                    {s.has_monetary_benefit && s.benefit_annual_inr > 0
                      ? `₹${s.benefit_annual_inr.toLocaleString('en-IN')}`
                      : '—'}
                  </td>
                  <td className="p-3">
                    <span
                      className="px-2 py-0.5 rounded-full"
                      style={{
                        fontSize: '0.7rem',
                        backgroundColor: s.demo_ready ? 'rgba(19,136,8,0.1)' : 'rgba(255,153,51,0.1)',
                        color: s.demo_ready ? '#138808' : '#FF9933',
                      }}
                    >
                      {s.demo_ready ? 'Verified' : 'Pending'}
                    </span>
                  </td>
                  <td className="p-3">
                    <div className="flex gap-1">
                      <button className="p-1.5 rounded hover:bg-muted"><Eye className="w-3.5 h-3.5" /></button>
                      <button className="p-1.5 rounded hover:bg-muted"><Edit2 className="w-3.5 h-3.5" /></button>
                      <button className="p-1.5 rounded hover:bg-muted text-destructive"><Trash2 className="w-3.5 h-3.5" /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

