                  <tr><td colSpan={5} className="py-4 text-center text-muted-foreground" style={{ fontSize: '0.8rem' }}>No sessions yet</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

