'use client';

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { v4Fallback } from '@/utils/uuid';
import type { SchemeResult } from '@/lib/api';

const ADMIN_EMAIL = process.env.NEXT_PUBLIC_ADMIN_EMAIL || 'aniruddhvijay2k7@gmail.com';

export interface ChatMessage {
  id: string; role: 'user'|'bot'; text: string; audioB64?: string; isVoice?: boolean;
}

interface AppState {
  sessionId: string;
  isLoggedIn: boolean;
  isAdmin: boolean;
  user: { id:string; email:string; name:string; role:string; isAdmin?: boolean } | null;
  messages: ChatMessage[];
  chatState: 'intake'|'match'|'guide'|'form_fill'|'goodbye';
  profile: Record<string, unknown>;
  schemes: SchemeResult[];
  gapValue: number;
  currentLanguage: string;
  isVoicePlaying: boolean;
  lastInputTime: number;
  applications: Record<string, unknown>;
  activeSchemeId: string | null;
  addMessage: (m: ChatMessage) => void;
  setProfile: (p: Record<string, unknown>) => void;
  mergeProfile: (p: Record<string, unknown>) => void;
  setSchemes: (s: SchemeResult[]) => void;
  setGapValue: (v: number) => void;
  setChatState: (s: AppState['chatState']) => void;
  setLanguage: (l: string) => void;
  setVoicePlaying: (b: boolean) => void;
  updateLastInputTime: () => void;
  setActiveScheme: (id: string|null) => void;
  login: (userData: { name: string; email: string; token: string }) => void;
  loginWithToken: (token: string, user: AppState['user']) => void;
  logout: () => void;
  resetChatSession: () => void;
  addApplication: (ref: string, data: unknown) => void;
}

const Ctx = createContext<AppState>({} as AppState);

function getStorage(key: string): string | null {
  if (typeof window === 'undefined') return null;
  try { return localStorage.getItem(key); } catch { return null; }
}

function setStorage(key: string, value: string): void {
  if (typeof window === 'undefined') return;
  try { localStorage.setItem(key, value); } catch {}
}

function removeStorage(key: string): void {
  if (typeof window === 'undefined') return;
  try { localStorage.removeItem(key); } catch {}
}

export function AppProvider({ children }: { children: React.ReactNode }) {
  const [sessionId, setSessionId] = useState(() => {
    const e = getStorage('js_session_id');
    if (e) return e;
    const n = v4Fallback();
    setStorage('js_session_id', n);
    return n;
  });
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [user, setUser] = useState<AppState['user']>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [chatState, setChatState] = useState<AppState['chatState']>('intake');
  const [profile, setProfileState] = useState<Record<string,unknown>>({});
  const [schemes, setSchemes] = useState<SchemeResult[]>([]);
  const [gapValue, setGapValue] = useState(0);
  const [currentLanguage, setCurrentLanguage] = useState(() => {
    return getStorage('js_language') || 'hi';
  });
  const [isVoicePlaying, setIsVoicePlaying] = useState(false);
  const [lastInputTime, setLastInputTime] = useState(Date.now());
  const [applications, setApplications] = useState<Record<string,unknown>>({});
  const [activeSchemeId, setActiveSchemeId] = useState<string|null>(null);

  const toUserRecord = useCallback((raw: unknown) => {
    if (!raw || typeof raw !== 'object') return null;
    const src = raw as Record<string, unknown>;
    const email = typeof src.email === 'string' ? src.email : '';
    const name = typeof src.name === 'string' ? src.name : '';
    if (!email || !name) return null;

    const explicitIsAdmin = typeof src.isAdmin === 'boolean' ? src.isAdmin : undefined;
    const role = typeof src.role === 'string' ? src.role : explicitIsAdmin ? 'admin' : 'citizen';
    const id = typeof src.id === 'string' ? src.id : email;
    const isAdmin = explicitIsAdmin ?? email === ADMIN_EMAIL;

    return { id, email, name, role, isAdmin };
  }, []);

  useEffect(() => {
    const stored = getStorage('js_user');
    const token = getStorage('js_auth_token');
    if (stored && token) {
      try {
        const parsed = JSON.parse(stored);
        const hydratedUser = toUserRecord(parsed);
        if (hydratedUser) {
          setIsLoggedIn(true);
          setUser(hydratedUser);
        }
      } catch {}
    }
    const a = getStorage('js_applications');
    if (a) try { setApplications(JSON.parse(a)); } catch {}
  }, [toUserRecord]);

  const addMessage    = useCallback((m: ChatMessage) => setMessages(p => [...p, m]), []);
  const setProfile    = useCallback((p: Record<string,unknown>) => setProfileState(p), []);
  const mergeProfile  = useCallback((p: Record<string,unknown>) => setProfileState(prev => ({...prev,...p})), []);
  const setLanguage   = useCallback((l: string) => {
    setCurrentLanguage(l);
    if (typeof document !== 'undefined') document.documentElement.lang = l;
    setStorage('js_language', l);
  }, []);
  const updateLastInputTime = useCallback(() => setLastInputTime(Date.now()), []);
  const setActiveScheme = useCallback((id: string|null) => setActiveSchemeId(id), []);

  const resetChatSession = useCallback(() => {
    const newId = v4Fallback();
    setStorage('js_session_id', newId);
    setSessionId(newId);
    setMessages([]);
    setProfileState({});
    setChatState('intake');
    setSchemes([]);
    setGapValue(0);
    setActiveSchemeId(null);
  }, []);

  const login = useCallback((userData: { name: string; email: string; token: string }) => {
    const isAdmin = userData.email === ADMIN_EMAIL;
    const nextUser = {
      id: userData.email,
      name: userData.name,
      email: userData.email,
      role: isAdmin ? 'admin' : 'citizen',
      isAdmin,
    };

    setIsLoggedIn(true);
    setUser(nextUser);
    setStorage('js_auth_token', userData.token);
    setStorage('js_user', JSON.stringify({
      name: userData.name,
      email: userData.email,
      isAdmin,
    }));
    resetChatSession();
  }, [resetChatSession]);

  const loginWithToken = useCallback((token: string, u: AppState['user']) => {
    if (!u) return;
    login({
      name: u.name,
      email: u.email,
      token,
    });
  }, [login]);

  const logout = useCallback(() => {
    removeStorage('js_auth_token');
    removeStorage('js_user');
    setIsLoggedIn(false);
    setUser(null);
    resetChatSession();
  }, [resetChatSession]);

  const addApplication = useCallback((ref: string, data: unknown) => {
    setApplications(prev => {
      const updated = {...prev, [ref]: data};
      setStorage('js_applications', JSON.stringify(updated));
      return updated;
    });
  }, []);

  return (
    <Ctx.Provider value={{
      sessionId, isLoggedIn, isAdmin: !!user?.isAdmin, user, messages, chatState, profile, schemes, gapValue,
      currentLanguage, isVoicePlaying, lastInputTime, applications, activeSchemeId,
      addMessage, setProfile, mergeProfile, setSchemes, setGapValue, setChatState,
      setLanguage, setVoicePlaying: setIsVoicePlaying, updateLastInputTime,
      setActiveScheme, login, loginWithToken, logout, resetChatSession, addApplication,
    }}>
      {children}
    </Ctx.Provider>
  );
}

export const useApp = () => useContext(Ctx);

import withPWA from '@ducanh2912/next-pwa';
import type { NextConfig } from 'next';

const withBundleAnalyzer = require('@next/bundle-analyzer')({
  enabled: process.env.ANALYZE === 'true',
});

const nextConfig: NextConfig = {
  images: {
    remotePatterns: [
      { protocol: 'https', hostname: '*.supabase.co' },
    ],
  },

  env: {
    NEXT_PUBLIC_API_URL: process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000',
  },

  async headers() {
    return [
      {
        source: '/(.*)',
        headers: [
          { key: 'X-Content-Type-Options', value: 'nosniff' },
          { key: 'X-Frame-Options', value: 'DENY' },
          { key: 'X-XSS-Protection', value: '1; mode=block' },
        ],
      },
    ];
  },

  async redirects() {
    return [
      {
        source: '/landing',
        destination: '/',
        permanent: false,
      },
    ];
  },
};

export default withBundleAnalyzer(withPWA({
  dest: 'public',
  cacheOnFrontEndNav: true,
  aggressiveFrontEndNavCaching: true,
  reloadOnOnline: true,
  disable: process.env.NODE_ENV === 'development',
  workboxOptions: {
    disableDevLogs: true,
    runtimeCaching: [
      {
        urlPattern: /^https:\/\/jan-saathi\.vercel\.app\/schemes/,
        handler: 'StaleWhileRevalidate',
        options: {
          cacheName: 'scheme-pages',
          expiration: { maxEntries: 100, maxAgeSeconds: 24 * 60 * 60 },
        },
      },
      {
        urlPattern: /^https:\/\/.*\.supabase\.co\/rest\/v1\/schemes/,
        handler: 'CacheFirst',
        options: {
          cacheName: 'scheme-data',
          expiration: { maxEntries: 200, maxAgeSeconds: 60 * 60 },
          cacheableResponse: { statuses: [0, 200] },
        },
      },
      {
        urlPattern: /^https:\/\/fonts\.(googleapis|gstatic)\.com/,
        handler: 'CacheFirst',
        options: {
          cacheName: 'google-fonts',
          expiration: { maxEntries: 10, maxAgeSeconds: 365 * 24 * 60 * 60 },
        },
      },
      {
        urlPattern: /\/api\/(chat|voice)/,
        handler: 'NetworkFirst',
        options: {
          cacheName: 'api-calls',
          networkTimeoutSeconds: 10,
          expiration: { maxEntries: 50, maxAgeSeconds: 5 * 60 },
        },
      },
    ],
  },
})(nextConfig));

import { describe, it, expect, vi } from 'vitest';
import React from 'react';
import { render, screen, fireEvent, act } from '@testing-library/react';
import { AppProvider, useApp } from '@/context/AppContext';

// Mock the uuid utility
vi.mock('@/utils/uuid', () => ({
  v4Fallback: () => 'test-uuid-1234',
}));

// Mock next-auth
vi.mock('next-auth/react', () => ({
  SessionProvider: ({ children }: { children: React.ReactNode }) => <>{children}</>,
  useSession: () => ({ data: null, status: 'unauthenticated' }),
}));

// Test consumer component
const TestConsumer = () => {
  const { profile, mergeProfile, chatState, setChatState, sessionId, currentLanguage, setLanguage, gapValue, setGapValue, schemes, setSchemes, isLoggedIn, logout, resetChatSession, addMessage, messages } = useApp();
  return (
    <div>
      <div data-testid="state">{(profile.state as string) || 'empty'}</div>
      <div data-testid="chatState">{chatState}</div>
      <div data-testid="sessionId">{sessionId}</div>
      <div data-testid="language">{currentLanguage}</div>
      <div data-testid="gapValue">{gapValue}</div>
      <div data-testid="schemeCount">{schemes.length}</div>
      <div data-testid="isLoggedIn">{isLoggedIn ? 'yes' : 'no'}</div>
      <div data-testid="messageCount">{messages.length}</div>
      <button data-testid="merge-btn" onClick={() => mergeProfile({ state: 'Maharashtra' })}>Merge</button>
      <button data-testid="state-btn" onClick={() => setChatState('match')}>Match</button>
      <button data-testid="lang-btn" onClick={() => setLanguage('bn')}>Bengali</button>
      <button data-testid="gap-btn" onClick={() => setGapValue(6000)}>Gap</button>
      <button data-testid="logout-btn" onClick={logout}>Logout</button>
      <button data-testid="reset-btn" onClick={resetChatSession}>Reset</button>
      <button data-testid="msg-btn" onClick={() => addMessage({ id: '1', role: 'user', text: 'hello' })}>Msg</button>
    </div>
  );
};

const Wrapper = ({ children }: { children: React.ReactNode }) => (
  <AppProvider>{children}</AppProvider>
);

describe('AppContext', () => {
  it('starts with empty profile', () => {
    render(<TestConsumer />, { wrapper: Wrapper });
    expect(screen.getByTestId('state').textContent).toBe('empty');
  });

  it('initial chatState is intake', () => {
    render(<TestConsumer />, { wrapper: Wrapper });
    expect(screen.getByTestId('chatState').textContent).toBe('intake');
  });

  it('generates a session ID', () => {
    render(<TestConsumer />, { wrapper: Wrapper });
    const sessionId = screen.getByTestId('sessionId').textContent;
    expect(sessionId).toBeTruthy();
    expect(sessionId!.length).toBeGreaterThan(5);
  });

  it('default language is Hindi', () => {
    render(<TestConsumer />, { wrapper: Wrapper });
    expect(screen.getByTestId('language').textContent).toBe('hi');
  });

  it('mergeProfile updates state', () => {
    render(<TestConsumer />, { wrapper: Wrapper });
    fireEvent.click(screen.getByTestId('merge-btn'));
    expect(screen.getByTestId('state').textContent).toBe('Maharashtra');
  });

  it('setChatState transitions correctly', () => {
    render(<TestConsumer />, { wrapper: Wrapper });
    fireEvent.click(screen.getByTestId('state-btn'));
    expect(screen.getByTestId('chatState').textContent).toBe('match');
  });

  it('setLanguage updates current language', () => {
    render(<TestConsumer />, { wrapper: Wrapper });
    fireEvent.click(screen.getByTestId('lang-btn'));
    expect(screen.getByTestId('language').textContent).toBe('bn');
  });

  it('gap value starts at 0 and updates', () => {
    render(<TestConsumer />, { wrapper: Wrapper });
    expect(screen.getByTestId('gapValue').textContent).toBe('0');
    fireEvent.click(screen.getByTestId('gap-btn'));
    expect(screen.getByTestId('gapValue').textContent).toBe('6000');
  });

  it('starts not logged in', () => {
    render(<TestConsumer />, { wrapper: Wrapper });
    expect(screen.getByTestId('isLoggedIn').textContent).toBe('no');
  });

  it('addMessage appends to messages', () => {
    render(<TestConsumer />, { wrapper: Wrapper });
    expect(screen.getByTestId('messageCount').textContent).toBe('0');
    fireEvent.click(screen.getByTestId('msg-btn'));
    expect(screen.getByTestId('messageCount').textContent).toBe('1');
  });

  it('resetChatSession clears messages and profile', () => {
    render(<TestConsumer />, { wrapper: Wrapper });
    // Add data first
    fireEvent.click(screen.getByTestId('merge-btn'));
    fireEvent.click(screen.getByTestId('msg-btn'));
    expect(screen.getByTestId('state').textContent).toBe('Maharashtra');
    expect(screen.getByTestId('messageCount').textContent).toBe('1');
    // Reset
    fireEvent.click(screen.getByTestId('reset-btn'));
    expect(screen.getByTestId('state').textContent).toBe('empty');
    expect(screen.getByTestId('messageCount').textContent).toBe('0');
    expect(screen.getByTestId('chatState').textContent).toBe('intake');
  });
});

